import React, { useEffect, useState, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';
import { useToast } from '../components/ui/Toast';

interface Generation {
  id: string;
  target_company: string;
  match_score: number;
  application_status: string;
  created_at: string;
  resume_html?: string;
  applicant_name?: string;
}

const STATUS_COLUMNS = [
  { key: 'Tailored', label: 'Tailored', color: '#9B8EA6' },
  { key: 'Applied', label: 'Applied', color: '#7B9AB4' },
  { key: 'Interviewing', label: 'Interviewing', color: '#f59e0b' },
  { key: 'Offer', label: 'Offer', color: '#10b981' },
  { key: 'Rejected', label: 'Rejected', color: '#ef4444' },
];

export default function HistoryPage() {
  const { user, supabase, isLoading } = useAuth();
  const brand = useBrand();
  const { showToast } = useToast();
  const navigate = useNavigate();
  const [generations, setGenerations] = useState<Generation[]>([]);
  const [filter, setFilter] = useState('');
  const [searchQuery, setSearchQuery] = useState('');

  // Detail modal state
  const [selectedGen, setSelectedGen] = useState<Generation | null>(null);
  const [detailStatus, setDetailStatus] = useState('');
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);

  // Drag & drop state
  const dragItemRef = useRef<string | null>(null);
  const [dragOverCol, setDragOverCol] = useState<string | null>(null);

  useEffect(() => {
    if (isLoading) return;
    if (!user) { navigate('/login'); return; }

    async function load() {
      const { data } = await supabase
        .from('generations')
        .select('id, target_company, match_score, application_status, created_at, resume_html, applicant_name')
        .eq('user_id', user!.id)
        .order('created_at', { ascending: false });

      if (data) setGenerations(data);
    }
    load();
  }, [user, supabase, isLoading, navigate]);

  const updateStatus = useCallback(async (id: string, newStatus: string) => {
    await supabase
      .from('generations')
      .update({ application_status: newStatus })
      .eq('id', id);

    setGenerations(prev =>
      prev.map(g => g.id === id ? { ...g, application_status: newStatus } : g)
    );
    showToast(`Moved to ${newStatus}`);
  }, [supabase, showToast]);

  const handleDelete = useCallback(async (id: string) => {
    const { error } = await supabase
      .from('generations')
      .delete()
      .eq('id', id);

    if (!error) {
      setGenerations(prev => prev.filter(g => g.id !== id));
      showToast('Application deleted');
      setSelectedGen(null);
    } else {
      showToast('Failed to delete', true);
    }
    setConfirmDelete(null);
  }, [supabase, showToast]);

  /* ---- Drag & Drop handlers ---- */
  const onDragStart = useCallback((e: React.DragEvent, genId: string) => {
    dragItemRef.current = genId;
    e.dataTransfer.effectAllowed = 'move';
    (e.currentTarget as HTMLElement).style.opacity = '0.5';
  }, []);

  const onDragEnd = useCallback((e: React.DragEvent) => {
    (e.currentTarget as HTMLElement).style.opacity = '1';
    dragItemRef.current = null;
    setDragOverCol(null);
  }, []);

  const onDragOver = useCallback((e: React.DragEvent, colKey: string) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    setDragOverCol(colKey);
  }, []);

  const onDragLeave = useCallback(() => {
    setDragOverCol(null);
  }, []);

  const onDrop = useCallback(
    (e: React.DragEvent, targetStatus: string) => {
      e.preventDefault();
      setDragOverCol(null);
      const genId = dragItemRef.current;
      if (!genId) return;

      const gen = generations.find(g => g.id === genId);
      if (gen && (gen.application_status || 'Tailored') !== targetStatus) {
        updateStatus(genId, targetStatus);
      }
      dragItemRef.current = null;
    },
    [generations, updateStatus],
  );

  /* ---- Detail modal helpers ---- */
  const openDetail = useCallback((gen: Generation) => {
    setSelectedGen(gen);
    setDetailStatus(gen.application_status || 'Tailored');
    setConfirmDelete(null);
  }, []);

  const closeDetail = useCallback(() => {
    setSelectedGen(null);
    setConfirmDelete(null);
  }, []);

  const saveDetailStatus = useCallback(async () => {
    if (!selectedGen) return;
    if (detailStatus !== (selectedGen.application_status || 'Tailored')) {
      await updateStatus(selectedGen.id, detailStatus);
      setSelectedGen(prev => prev ? { ...prev, application_status: detailStatus } : null);
    }
  }, [selectedGen, detailStatus, updateStatus]);

  const filtered = generations.filter(g => {
    if (filter && (g.application_status || 'Tailored') !== filter) return false;
    if (searchQuery && !g.target_company?.toLowerCase().includes(searchQuery.toLowerCase())) return false;
    return true;
  });

  if (isLoading) return <div style={{ textAlign: 'center', padding: '4rem', color: 'var(--text-secondary)' }}>Loading...</div>;

  return (
    <div className="kanban-page" style={{ maxWidth: '1100px', margin: '0 auto', padding: '2rem 1.5rem' }}>
      <div className="kanban-header" style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '1rem' }}>
        <h1 style={{ fontSize: '1.5rem', margin: 0, color: 'var(--text-primary)' }}>Application History</h1>
        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
          <input
            type="text"
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            placeholder="Search companies..."
            style={{ width: '180px' }}
          />
          <select value={filter} onChange={e => setFilter(e.target.value)}>
            <option value="">All Statuses</option>
            {STATUS_COLUMNS.map(col => (
              <option key={col.key} value={col.key}>{col.label}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Kanban Board */}
      <div className="kanban-board" style={{ display: 'flex', gap: '0.75rem', overflowX: 'auto', minHeight: '400px' }}>
        {STATUS_COLUMNS.map(col => {
          const items = filtered.filter(g => (g.application_status || 'Tailored') === col.key);
          const isOver = dragOverCol === col.key;
          return (
            <div
              key={col.key}
              className="kanban-column glass-panel"
              style={{
                flex: '1 0 200px',
                minWidth: '200px',
                padding: '0.75rem',
                display: 'flex',
                flexDirection: 'column',
                transition: 'box-shadow 0.15s ease',
                boxShadow: isOver ? `inset 0 0 0 2px ${col.color}` : undefined,
              }}
              onDragOver={e => onDragOver(e, col.key)}
              onDragLeave={onDragLeave}
              onDrop={e => onDrop(e, col.key)}
            >
              <div className="column-header" style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', marginBottom: '0.75rem', paddingBottom: '0.5rem', borderBottom: `2px solid ${col.color}` }}>
                <span style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-primary)' }}>{col.label}</span>
                <span style={{ fontSize: '0.7rem', color: 'var(--text-secondary)', marginLeft: 'auto' }}>{items.length}</span>
              </div>

              <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '0.4rem', overflowY: 'auto' }}>
                {items.map(gen => (
                  <div
                    key={gen.id}
                    className="asym-card"
                    draggable
                    onDragStart={e => onDragStart(e, gen.id)}
                    onDragEnd={onDragEnd}
                    style={{ padding: '0.6rem', cursor: 'grab', minHeight: '58px', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}
                    onClick={() => openDetail(gen)}
                  >
                    <div style={{ fontWeight: 600, fontSize: '0.8rem', color: 'var(--text-primary)', marginBottom: '0.25rem' }}>
                      {gen.target_company || 'Unknown'}
                    </div>
                    <div style={{ fontSize: '0.7rem', color: 'var(--text-secondary)', display: 'flex', justifyContent: 'space-between' }}>
                      <span>{new Date(gen.created_at).toLocaleDateString()}</span>
                      {gen.match_score > 0 && <span style={{ color: gen.match_score >= 80 ? '#10b981' : '#f59e0b' }}>{gen.match_score}%</span>}
                    </div>
                  </div>
                ))}
                {items.length === 0 && (
                  <div style={{ textAlign: 'center', padding: '1.5rem 0.5rem', color: 'var(--text-secondary)', fontSize: '0.75rem', opacity: 0.6 }}>
                    <i className="fa-solid fa-inbox" style={{ display: 'block', fontSize: '1.2rem', marginBottom: '0.4rem' }} />
                    No items
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Detail Modal */}
      {selectedGen && (
        <div
          style={{
            position: 'fixed',
            inset: 0,
            zIndex: 9000,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            background: 'rgba(0,0,0,0.6)',
            padding: '1rem',
          }}
          onClick={closeDetail}
        >
          <div
            className="glass-panel"
            style={{
              maxWidth: '480px',
              width: '100%',
              padding: '1.5rem',
            }}
            onClick={e => e.stopPropagation()}
          >
            {/* Header */}
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.25rem' }}>
              <h2 style={{ margin: 0, fontSize: '1.15rem', color: 'var(--text-primary)' }}>
                {selectedGen.target_company || 'Unknown'}
              </h2>
              <button className="btn ghost-btn" onClick={closeDetail} style={{ padding: '0.3rem 0.5rem', fontSize: '0.85rem' }}>
                <i className="fa-solid fa-xmark" />
              </button>
            </div>

            {/* Info grid */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
              {/* Match score */}
              {selectedGen.match_score > 0 && (
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                  <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>Match Score:</span>
                  <span style={{
                    fontWeight: 700,
                    fontSize: '1rem',
                    color: selectedGen.match_score >= 80 ? '#10b981' : selectedGen.match_score >= 60 ? '#f59e0b' : '#ef4444',
                  }}>
                    {selectedGen.match_score}%
                  </span>
                </div>
              )}

              {/* Date */}
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>Created:</span>
                <span style={{ fontSize: '0.82rem', color: 'var(--text-primary)' }}>
                  {new Date(selectedGen.created_at).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' })}
                </span>
              </div>

              {/* Status dropdown */}
              <div>
                <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                  Status
                </label>
                <select
                  value={detailStatus}
                  onChange={e => {
                    setDetailStatus(e.target.value);
                    // Auto-save status change
                    const newStatus = e.target.value;
                    if (selectedGen && newStatus !== (selectedGen.application_status || 'Tailored')) {
                      updateStatus(selectedGen.id, newStatus);
                      setSelectedGen(prev => prev ? { ...prev, application_status: newStatus } : null);
                    }
                  }}
                >
                  {STATUS_COLUMNS.map(col => (
                    <option key={col.key} value={col.key}>{col.label}</option>
                  ))}
                </select>
              </div>

              {/* View resume button */}
              <button
                className="btn secondary-btn large-action-btn"
                onClick={() => navigate(`/results?id=${selectedGen.id}`)}
                style={{ width: '100%' }}
              >
                <i className="fa-solid fa-file-lines" style={{ marginRight: '0.35rem' }} />
                View Tailored Resume
              </button>

              {/* Track in Job Tracker */}
              <button
                className="btn ghost-btn"
                onClick={() => navigate(`/jobs`)}
                style={{ width: '100%', fontSize: '0.82rem' }}
              >
                <i className="fa-solid fa-clipboard-list" style={{ marginRight: '0.35rem' }} />
                Manage in Job Tracker (notes, dates, contacts)
              </button>
            </div>

            {/* Footer with delete */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '1.5rem', paddingTop: '1rem', borderTop: '1px solid var(--border-color, rgba(255,255,255,0.08))' }}>
              <div>
                {confirmDelete === selectedGen.id ? (
                  <div style={{ display: 'flex', gap: '0.4rem', alignItems: 'center' }}>
                    <span style={{ fontSize: '0.78rem', color: '#ef4444' }}>Delete this?</span>
                    <button
                      className="btn ghost-btn"
                      onClick={() => handleDelete(selectedGen.id)}
                      style={{ padding: '0.3rem 0.6rem', fontSize: '0.78rem', color: '#ef4444' }}
                    >
                      Yes
                    </button>
                    <button
                      className="btn ghost-btn"
                      onClick={() => setConfirmDelete(null)}
                      style={{ padding: '0.3rem 0.6rem', fontSize: '0.78rem' }}
                    >
                      No
                    </button>
                  </div>
                ) : (
                  <button
                    className="btn ghost-btn"
                    onClick={() => setConfirmDelete(selectedGen.id)}
                    style={{ padding: '0.3rem 0.6rem', fontSize: '0.78rem', color: '#ef4444' }}
                  >
                    <i className="fa-solid fa-trash" style={{ marginRight: '0.25rem' }} />
                    Delete
                  </button>
                )}
              </div>
              <button className="btn ghost-btn" onClick={closeDetail}>
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
